import{_ as t,c as a,o as n,a1 as o}from"./chunks/framework.DILC4Csi.js";const h=JSON.parse('{"title":"Quick Start: Master Plannotator | Plannotator","description":"Master Plannotator in 5 minutes. Install CLI, configure plugins, and complete your first plan and code review with visual annotations.","frontmatter":{"title":"Quick Start: Master Plannotator | Plannotator","subtitle":"Quick Start: Master Plannotator in 5 Minutes","sidebarTitle":"Quick Start","description":"Master Plannotator in 5 minutes. Install CLI, configure plugins, and complete your first plan and code review with visual annotations.","tags":["Quick Start","Getting Started","Installation","Claude Code","OpenCode"],"order":1},"headers":[],"relativePath":"backnotprop/plannotator/start/getting-started/index.md","filePath":"backnotprop/plannotator/start/getting-started/index.md"}'),s={name:"backnotprop/plannotator/start/getting-started/index.md"};function i(l,e,r,p,d,c){return n(),a("div",null,[...e[0]||(e[0]=[o(`<h1 id="quick-start-master-plannotator-in-5-minutes" tabindex="-1">Quick Start: Master Plannotator in 5 Minutes <a class="header-anchor" href="#quick-start-master-plannotator-in-5-minutes" aria-label="Permalink to &quot;Quick Start: Master Plannotator in 5 Minutes&quot;">​</a></h1><h2 id="what-you-ll-learn" tabindex="-1">What You&#39;ll Learn <a class="header-anchor" href="#what-you-ll-learn" aria-label="Permalink to &quot;What You&#39;ll Learn&quot;">​</a></h2><ul><li>✅ Understand Plannotator&#39;s core features and use cases</li><li>✅ Install Plannotator in under 5 minutes</li><li>✅ Configure Claude Code or OpenCode integration</li><li>✅ Complete your first plan review and code review</li></ul><h2 id="the-problem" tabindex="-1">The Problem <a class="header-anchor" href="#the-problem" aria-label="Permalink to &quot;The Problem&quot;">​</a></h2><p><strong>Plannotator</strong> is an interactive review tool designed for Claude Code and OpenCode that helps you solve these problems:</p><p><strong>Pain Point 1</strong>: AI-generated implementation plans are read in terminals with large text volumes and unclear structure, making review exhausting.</p><p><strong>Pain Point 2</strong>: When providing feedback to AI, you can only use text descriptions like &quot;delete paragraph 3&quot; or &quot;modify this function&quot;, which is inefficient.</p><p><strong>Pain Point 3</strong>: During code review, you need to switch between multiple terminals or IDEs, making it hard to stay focused.</p><p><strong>Pain Point 4</strong>: Team members want to participate in reviews but don&#39;t know how to share plan content.</p><p><strong>What Plannotator Does for You</strong>:</p><ul><li>Visual UI replaces terminal reading with clear structure</li><li>Select text to add annotations (delete, replace, comment) for precise feedback</li><li>Visual Git diff review with line-level comments</li><li>URL sharing for team collaboration without backend</li></ul><h2 id="when-to-use-this" tabindex="-1">When to Use This <a class="header-anchor" href="#when-to-use-this" aria-label="Permalink to &quot;When to Use This&quot;">​</a></h2><p><strong>Use Cases</strong>:</p><ul><li>Using Claude Code or OpenCode for AI-assisted development</li><li>Need to review AI-generated implementation plans</li><li>Need to review code changes</li><li>Need to share plans or code review results with team members</li></ul><p><strong>Not Suitable For</strong>:</p><ul><li>Pure manual coding (no AI-generated plans)</li><li>Already have complete code review processes (like GitHub PR)</li><li>Don&#39;t need visual review tools</li></ul><h2 id="core-concepts" tabindex="-1">Core Concepts <a class="header-anchor" href="#core-concepts" aria-label="Permalink to &quot;Core Concepts&quot;">​</a></h2><h3 id="what-is-plannotator" tabindex="-1">What is Plannotator <a class="header-anchor" href="#what-is-plannotator" aria-label="Permalink to &quot;What is Plannotator&quot;">​</a></h3><p><strong>Plannotator</strong> is an interactive review tool designed for AI Coding Agents (Claude Code, OpenCode), primarily providing two features:</p><ol><li><strong>Plan Review</strong>: Visually review AI-generated implementation plans, supporting annotations, approval, or rejection</li><li><strong>Code Review</strong>: Visually review Git diffs, supporting line-level comments and multiple view modes</li></ol><h3 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────┐</span></span>
<span class="line"><span>│  AI Agent      │</span></span>
<span class="line"><span>│  (generates)   │</span></span>
<span class="line"><span>└────────┬────────┘</span></span>
<span class="line"><span>          │</span></span>
<span class="line"><span>          ▼</span></span>
<span class="line"><span>┌─────────────────┐</span></span>
<span class="line"><span>│  Plannotator   │  ← Local HTTP server</span></span>
<span class="line"><span>│  (visual UI)   │</span></span>
<span class="line"><span>└────────┬────────┘</span></span>
<span class="line"><span>          │</span></span>
<span class="line"><span>          ▼</span></span>
<span class="line"><span>┌─────────────────┐</span></span>
<span class="line"><span>│  Browser       │</span></span>
<span class="line"><span>│  (user review) │</span></span>
<span class="line"><span>└─────────────────┘</span></span></code></pre></div><p><strong>Core Flow</strong>:</p><ol><li>AI Agent completes plan or code changes</li><li>Plannotator starts a local HTTP server and opens browser</li><li>User views plan/code in browser and adds annotations</li><li>User approves or rejects, Plannotator returns decision to AI Agent</li><li>AI Agent continues implementation or modifies based on feedback</li></ol><h3 id="security" tabindex="-1">Security <a class="header-anchor" href="#security" aria-label="Permalink to &quot;Security&quot;">​</a></h3><p><strong>All data processed locally</strong>, never uploaded to cloud:</p><ul><li>Plan content, code diffs, and annotations are stored on your local machine</li><li>Local HTTP server uses random port (or fixed port)</li><li>URL sharing is implemented by compressing data into URL hash, no backend needed</li></ul><h2 id="🎒-prerequisites" tabindex="-1">🎒 Prerequisites <a class="header-anchor" href="#🎒-prerequisites" aria-label="Permalink to &quot;🎒 Prerequisites&quot;">​</a></h2><p><strong>System Requirements</strong>:</p><ul><li>Operating System: macOS / Linux / Windows / WSL</li><li>Runtime: Bun (install script handles this automatically)</li><li>AI Environment: Claude Code 2.1.7+ or OpenCode</li></ul><p><strong>Installation Options</strong>:</p><ul><li>If using Claude Code: Need CLI + plugin</li><li>If using OpenCode: Need plugin configuration</li><li>If only doing code review: Only CLI needed</li></ul><h2 id="follow-along" tabindex="-1">Follow Along <a class="header-anchor" href="#follow-along" aria-label="Permalink to &quot;Follow Along&quot;">​</a></h2><h3 id="step-1-install-plannotator-cli" tabindex="-1">Step 1: Install Plannotator CLI <a class="header-anchor" href="#step-1-install-plannotator-cli" aria-label="Permalink to &quot;Step 1: Install Plannotator CLI&quot;">​</a></h3><p><strong>macOS / Linux / WSL</strong>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://plannotator.ai/install.sh</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> bash</span></span></code></pre></div><p><strong>Windows PowerShell</strong>:</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">irm https:</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">//</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">plannotator.ai</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">install.ps1 </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> iex</span></span></code></pre></div><p><strong>Windows CMD</strong>:</p><div class="language-cmd vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">cmd</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">curl </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">fsSL https://plannotator.ai/install.cmd </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">o install.cmd </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&amp;&amp;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> install.cmd </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&amp;&amp;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> del install.cmd</span></span></code></pre></div><p><strong>What You Should See</strong>: The install script will automatically download Plannotator CLI, add it to your system PATH, and display the version number (e.g., &quot;plannotator v0.6.7 installed to ...&quot;).</p><div class="tip custom-block"><p class="custom-block-title">What does the install script do?</p><p>The install script will:</p><ol><li>Download the latest version of Plannotator CLI</li><li>Add to system PATH</li><li>Clean up any existing old versions</li><li>Automatically install the <code>/plannotator-review</code> command (for code review)</li></ol></div><h3 id="step-2-configure-claude-code-optional" tabindex="-1">Step 2: Configure Claude Code (Optional) <a class="header-anchor" href="#step-2-configure-claude-code-optional" aria-label="Permalink to &quot;Step 2: Configure Claude Code (Optional)&quot;">​</a></h3><p>If you use Claude Code, you need to install the plugin.</p><p><strong>Run in Claude Code</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/plugin marketplace add backnotprop/plannotator</span></span>
<span class="line"><span>/plugin install plannotator@plannotator</span></span></code></pre></div><p><strong>Important</strong>: After installing the plugin, <strong>you MUST restart Claude Code</strong> for the hooks to take effect.</p><p><strong>What You Should See</strong>: After successful plugin installation, <code>plannotator</code> will appear in Claude Code&#39;s plugin list.</p><div class="info custom-block"><p class="custom-block-title">Manual Configuration (Optional)</p><p>If you don&#39;t want to use the plugin system, you can manually configure hooks. See <a href="./../installation-claude-code/">Claude Code Plugin Installation</a> section.</p></div><h3 id="step-3-configure-opencode-optional" tabindex="-1">Step 3: Configure OpenCode (Optional) <a class="header-anchor" href="#step-3-configure-opencode-optional" aria-label="Permalink to &quot;Step 3: Configure OpenCode (Optional)&quot;">​</a></h3><p>If you use OpenCode, you need to edit the <code>opencode.json</code> file.</p><p><strong>Edit <code>opencode.json</code></strong>:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;$schema&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://opencode.ai/config.json&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;plugin&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;@plannotator/opencode@latest&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><strong>Restart OpenCode</strong>.</p><p><strong>What You Should See</strong>: After restart, OpenCode will automatically load the plugin and the <code>submit_plan</code> tool will be available.</p><h3 id="step-4-first-plan-review-claude-code-example" tabindex="-1">Step 4: First Plan Review (Claude Code Example) <a class="header-anchor" href="#step-4-first-plan-review-claude-code-example" aria-label="Permalink to &quot;Step 4: First Plan Review (Claude Code Example)&quot;">​</a></h3><p><strong>Trigger</strong>: Have Claude Code generate an implementation plan and call <code>ExitPlanMode</code>.</p><p><strong>Example Dialogue</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>User: Help me write an implementation plan for user authentication module</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Claude: Sure, here&#39;s the implementation plan:</span></span>
<span class="line"><span>1. Create user model</span></span>
<span class="line"><span>2. Implement registration API</span></span>
<span class="line"><span>3. Implement login API</span></span>
<span class="line"><span>...</span></span>
<span class="line"><span>(calls ExitPlanMode)</span></span></code></pre></div><p><strong>What You Should See</strong>:</p><ol><li>Browser automatically opens Plannotator UI</li><li>Shows AI-generated plan content</li><li>You can select plan text and add annotations (delete, replace, comment)</li><li>Bottom has &quot;Approve&quot; and &quot;Request Changes&quot; buttons</li></ol><p><strong>Actions</strong>:</p><ol><li>Review the plan in browser</li><li>If plan is fine, click <strong>Approve</strong> → AI continues implementation</li><li>If changes are needed, select text to modify, click <strong>Delete</strong>, <strong>Replace</strong>, or <strong>Comment</strong> → click <strong>Request Changes</strong></li></ol><p><strong>What You Should See</strong>: After clicking, browser will automatically close and Claude Code will receive your decision and continue execution.</p><h3 id="step-5-first-code-review" tabindex="-1">Step 5: First Code Review <a class="header-anchor" href="#step-5-first-code-review" aria-label="Permalink to &quot;Step 5: First Code Review&quot;">​</a></h3><p><strong>Run in project directory</strong>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/plannotator-review</span></span></code></pre></div><p><strong>What You Should See</strong>:</p><ol><li>Browser opens code review page</li><li>Shows Git diff (default is uncommitted changes)</li><li>Left side is file tree, right side is diff viewer</li><li>Click line numbers to select code range and add annotations</li></ol><p><strong>Actions</strong>:</p><ol><li>Browse code changes in diff viewer</li><li>Click line numbers to select code to review</li><li>Add annotations in right panel (comment/suggestion/concern)</li><li>Click <strong>Send Feedback</strong> to send to agent, or click <strong>LGTM</strong> to approve</li></ol><p><strong>What You Should See</strong>: After clicking Send Feedback, browser will close and formatted feedback content will be output in terminal, agent will process it automatically.</p><h2 id="checkpoint-✅" tabindex="-1">Checkpoint ✅ <a class="header-anchor" href="#checkpoint-✅" aria-label="Permalink to &quot;Checkpoint ✅&quot;">​</a></h2><p>After completing the above steps, you should be able to:</p><ul><li>[ ] Install script shows &quot;plannotator vX.X.X installed to ...&quot;</li><li>[ ] Trigger plan review in Claude Code, browser automatically opens UI</li><li>[ ] Select plan text in UI and add annotations</li><li>[ ] Click Approve or Request Changes, see browser close</li><li>[ ] Run <code>/plannotator-review</code>, see code review interface</li><li>[ ] Add line-level annotations in code review, click Send Feedback</li></ul><p><strong>If any step fails</strong>, see:</p><ul><li><a href="./../installation-claude-code/">Claude Code Installation Guide</a></li><li><a href="./../installation-opencode/">OpenCode Installation Guide</a></li><li><a href="./../../faq/common-problems/">Common Problems</a></li></ul><h2 id="common-pitfalls" tabindex="-1">Common Pitfalls <a class="header-anchor" href="#common-pitfalls" aria-label="Permalink to &quot;Common Pitfalls&quot;">​</a></h2><p><strong>Common Error 1</strong>: After installation, running <code>plannotator</code> shows &quot;command not found&quot;</p><p><strong>Cause</strong>: PATH environment variable not updated, or need to restart terminal.</p><p><strong>Solution</strong>:</p><ul><li>macOS/Linux: Run <code>source ~/.zshrc</code> or <code>source ~/.bashrc</code>, or restart terminal</li><li>Windows: Restart PowerShell or CMD</li></ul><p><strong>Common Error 2</strong>: After installing Claude Code plugin, plan review doesn&#39;t trigger</p><p><strong>Cause</strong>: Didn&#39;t restart Claude Code, hooks not生效.</p><p><strong>Solution</strong>: Fully quit Claude Code (not just closing window), then reopen.</p><p><strong>Common Error 3</strong>: Browser doesn&#39;t automatically open</p><p><strong>Cause</strong>: Might be remote mode (like devcontainer, SSH), or port is occupied.</p><p><strong>Solution</strong>:</p><ul><li>Check if <code>PLANNOTATOR_REMOTE=1</code> environment variable is set</li><li>Check URL output in terminal and manually open in browser</li><li>See <a href="./../../advanced/remote-mode/">Remote/Devcontainer Mode</a> for details</li></ul><p><strong>Common Error 4</strong>: Code review shows &quot;No changes&quot;</p><p><strong>Cause</strong>: No uncommitted git changes currently.</p><p><strong>Solution</strong>:</p><ul><li>Run <code>git status</code> first to confirm there are changes</li><li>Or run <code>git add</code> to stage some files</li><li>Or switch to other diff types (like last commit)</li></ul><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>Plannotator is a locally running review tool that improves plan review and code review efficiency through visual UI:</p><p><strong>Core Features</strong>:</p><ul><li><strong>Plan Review</strong>: Visually review AI-generated plans with precise annotations</li><li><strong>Code Review</strong>: Visually review Git diffs with line-level comments</li><li><strong>URL Sharing</strong>: Share review content without backend</li><li><strong>Third-party Integration</strong>: Automatically save approved plans to Obsidian/Bear</li></ul><p><strong>Core Advantages</strong>:</p><ul><li>Local execution, data security</li><li>Visual UI, improved efficiency</li><li>Precise feedback, reduced communication costs</li><li>Team collaboration, no account system needed</li></ul><h2 id="next-up" tabindex="-1">Next Up <a class="header-anchor" href="#next-up" aria-label="Permalink to &quot;Next Up&quot;">​</a></h2><blockquote><p>In the next lesson, we&#39;ll learn <strong><a href="./../installation-claude-code/">Claude Code Plugin Installation</a></strong>.</p><p>You&#39;ll learn:</p><ul><li>Detailed Claude Code plugin installation steps</li><li>Manual hook configuration methods</li><li>How to verify installation success</li><li>Common installation problem solutions</li></ul></blockquote><hr><h2 id="appendix-source-code-reference" tabindex="-1">Appendix: Source Code Reference <a class="header-anchor" href="#appendix-source-code-reference" aria-label="Permalink to &quot;Appendix: Source Code Reference&quot;">​</a></h2><details><summary><strong>Click to expand source code locations</strong></summary><blockquote><p>Updated: 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>Feature</th><th>File Path</th><th>Line Number</th></tr></thead><tbody><tr><td>CLI entry (plan review)</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/apps/hook/server/index.ts#L1-L50" target="_blank" rel="noreferrer"><code>apps/hook/server/index.ts</code></a></td><td>1-50</td></tr><tr><td>CLI entry (code review)</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/apps/hook/server/index.ts#L46-L84" target="_blank" rel="noreferrer"><code>apps/hook/server/index.ts</code></a></td><td>46-84</td></tr><tr><td>Plan review server</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/index.ts#L1-L200" target="_blank" rel="noreferrer"><code>packages/server/index.ts</code></a></td><td>1-200</td></tr><tr><td>Code review server</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/review.ts#L1-L150" target="_blank" rel="noreferrer"><code>packages/server/review.ts</code></a></td><td>1-150</td></tr><tr><td>Git tools</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/git.ts#L1-L100" target="_blank" rel="noreferrer"><code>packages/server/git.ts</code></a></td><td>1-100</td></tr><tr><td>Plan review UI</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/editor/App.tsx#L1-L200" target="_blank" rel="noreferrer"><code>packages/editor/App.tsx</code></a></td><td>1-200</td></tr><tr><td>Code review UI</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/review-editor/App.tsx#L1-L200" target="_blank" rel="noreferrer"><code>packages/review-editor/App.tsx</code></a></td><td>1-200</td></tr></tbody></table><p><strong>Key Constants</strong>:</p><ul><li><code>MAX_RETRIES = 5</code>: Port retry count (<code>packages/server/index.ts:80</code>)</li><li><code>RETRY_DELAY_MS = 500</code>: Port retry delay (<code>packages/server/index.ts:80</code>)</li></ul><p><strong>Key Functions</strong>:</p><ul><li><code>startPlannotatorServer()</code>: Start plan review server (<code>packages/server/index.ts</code>)</li><li><code>startReviewServer()</code>: Start code review server (<code>packages/server/review.ts</code>)</li><li><code>runGitDiff()</code>: Run git diff command (<code>packages/server/git.ts</code>)</li></ul><p><strong>Environment Variables</strong>:</p><ul><li><code>PLANNOTATOR_REMOTE</code>: Remote mode flag (<code>apps/hook/server/index.ts:17</code>)</li><li><code>PLANNOTATOR_PORT</code>: Fixed port (<code>apps/hook/server/index.ts:18</code>)</li><li><code>PLANNOTATOR_BROWSER</code>: Custom browser (<code>apps/hook/README.md:79</code>)</li><li><code>PLANNOTATOR_SHARE</code>: URL sharing toggle (<code>apps/hook/server/index.ts:44</code>)</li></ul></details>`,104)])])}const g=t(s,[["render",i]]);export{h as __pageData,g as default};
